    question: "Throw an exception using throw keyword.",
    mathSolution: "Manually throwing exceptions.",
    codeSolution: "using System;\n\nclass BankAccount\n{\n    private double balance;\n    \n    public void Withdraw(double amount)\n    {\n        if (amount <= 0)\n        {\n            throw new ArgumentException(\"Withdrawal amount must be positive\");\n        }\n        \n        if (amount > balance)\n        {\n            throw new InvalidOperationException(\"Insufficient funds\");\n        }\n        \n        balance -= amount;\n        Console.WriteLine($\"Withdrawn: ${amount}, New balance: ${balance}\");\n    }\n    \n    public void Deposit(double amount)\n    {\n        if (amount <= 0)\n        {\n            throw new ArgumentException(\"Deposit amount must be positive\");\n        }\n        balance += amount;\n        Console.WriteLine($\"Deposited: ${amount}, New balance: ${balance}\");\n    }\n}\n\nclass Program\n{\n    static void Main()\n    {\n        BankAccount account = new BankAccount();\n        \n        try\n        {\n            account.Deposit(100);\n            account.Withdraw(50);\n            account.Withdraw(100); // This will throw\n        }\n        catch (ArgumentException ex)\n        {\n            Console.WriteLine($\"Argument error: {ex.Message}\");\n        }\n        catch (InvalidOperationException ex)\n        {\n            Console.WriteLine($\"Operation error: {ex.Message}\");\n        }\n    }\n}",
    hint: "Use throw new ExceptionType(\"message\") to throw exceptions.",
